import { useCallback, useEffect, useMemo, useRef, useState } from "react";

type Status = "idle" | "uploading" | "streaming" | "completed" | "error";

type StartArgs = {
  templateFile: File | null;
  contextFiles: File[];
};

const EVENT_TYPES = [
  "response.code_interpreter_call_code.done",
  "response.output_text.done",
] as const;

export function useDocumentJob() {
  const [jobId, setJobId] = useState<string | null>(null);
  const [updates, setUpdates] = useState<string[]>([]);
  const [error, setError] = useState<string | null>(null);
  const [status, setStatus] = useState<Status>("idle");
  const eventSourceRef = useRef<EventSource | null>(null);

  const appendUpdate = useCallback((raw: string) => {
    if (!raw) return;

    let parsed: string;
    try {
      const json = JSON.parse(raw);
      parsed = typeof json === "string" ? json : JSON.stringify(json);
    } catch {
      parsed = raw;
    }

    const lines = parsed.replace(/['"]/g, "").split(/\r?\n/);
    setUpdates((prev) => prev.concat(lines));
  }, []);

  const reset = useCallback(() => {
    setJobId(null);
    setUpdates([]);
    setError(null);
    setStatus("idle");
    eventSourceRef.current?.close();
    eventSourceRef.current = null;
  }, []);

  const start = useCallback(
    async ({ templateFile, contextFiles }: StartArgs) => {
      setError(null);
      setUpdates([]);
      setStatus("uploading");

      if (!templateFile) {
        setError("Template file is missing.");
        setStatus("idle");
        return;
      }

      try {
        const form = new FormData();
        contextFiles.forEach((file) => form.append("contextFiles", file));
        form.append("templateFiles", templateFile);

        const res = await fetch("/api/upload", { method: "POST", body: form });
        if (!res.ok) {
          throw new Error("Upload failed.");
        }

        const { jobId: newJobId } = (await res.json()) as { jobId: string };
        setJobId(newJobId);
        setStatus("streaming");

        const es = new EventSource(`/api/stream/${newJobId}`);
        eventSourceRef.current = es;

        es.onerror = () => {
          if (es.readyState === EventSource.CLOSED) {
            setError("Connection interrupted. The generation may have failed.");
            setStatus("error");
          }
        };

        EVENT_TYPES.forEach((eventType) => {
          es.addEventListener(eventType, (event: MessageEvent) => {
            appendUpdate(event.data ?? "");
          });
        });

        es.addEventListener("completed", () => {
          setStatus("completed");
          es.close();
        });

        es.addEventListener("modelError", (event: MessageEvent) => {
          setError(`Server error: ${event.data}`);
          setStatus("error");
          es.close();
        });
      } catch (err) {
        setError(
          err instanceof Error
            ? err.message
            : "Failed to start generation. Please try again.",
        );
        setStatus("error");
      }
    },
    [appendUpdate],
  );

  useEffect(() => {
    return () => {
      eventSourceRef.current?.close();
    };
  }, []);

  const isStreaming = status === "streaming";
  const isCompleted = status === "completed";

  const state = useMemo(
    () => ({
      jobId,
      updates,
      error,
      status,
      isStreaming,
      isCompleted,
    }),
    [error, isCompleted, isStreaming, jobId, status, updates],
  );

  return { ...state, start, reset };
}
